102	    void apply_tilt(int dir_idx) { 
103	        if (dir_idx == 0) { // F (Up)
104	            for (int c = 0; c < GRID_SIZE; ++c) {
105	                int current_write_r = 0;
106	                for (int r = 0; r < GRID_SIZE; ++r) {
107	                    if (board[r][c] != 0) {
108	                        if (r != current_write_r) {
109	                            board[current_write_r][c] = board[r][c];
110	                            board[r][c] = 0;
111	                        }
112	                        current_write_r++;
113	                    }
114	                }
115	            }
116	        } else if (dir_idx == 1) { // B (Down)
117	            for (int c = 0; c < GRID_SIZE; ++c) {
118	                int current_write_r = GRID_SIZE - 1;
119	                for (int r = GRID_SIZE - 1; r >= 0; --r) {
120	                    if (board[r][c] != 0) {
121	                        if (r != current_write_r) {
122	                            board[current_write_r][c] = board[r][c];
123	                            board[r][c] = 0;
124	                        }
125	                        current_write_r--;
126	                    }
127	                }
128	            }
129	        } else if (dir_idx == 2) { // L (Left)
130	            for (int r = 0; r < GRID_SIZE; ++r) {
131	                int current_write_c = 0;
132	                for (int c = 0; c < GRID_SIZE; ++c) {
133	                    if (board[r][c] != 0) {
134	                        if (c != current_write_c) {
135	                            board[r][current_write_c] = board[r][c];
136	                            board[r][c] = 0;
137	                        }
138	                        current_write_c++;
139	                    }
140	                }
141	            }
142	        } else { // R (Right, dir_idx == 3)
143	            for (int r = 0; r < GRID_SIZE; ++r) {
144	                int current_write_c = GRID_SIZE - 1;
145	                for (int c = GRID_SIZE - 1; c >= 0; --c) {
146	                    if (board[r][c] != 0) {
147	                        if (c != current_write_c) {
148	                            board[r][current_write_c] = board[r][c];
149	                            board[r][c] = 0;
150	                        }
151	                        current_write_c--;
152	                    }
153	                }
154	            }
155	        }
156	        rebuild_candies_list_from_board();
157	    }
158	
159	    void rebuild_candies_list_from_board() {
160	        candies_list.clear(); 
161	        for (int r_idx = 0; r_idx < GRID_SIZE; ++r_idx) {
162	            for (int c_idx = 0; c_idx < GRID_SIZE; ++c_idx) {
163	                if (board[r_idx][c_idx] != 0) {
164	                    candies_list.push_back({r_idx, c_idx, board[r_idx][c_idx]});
165	                }
166	            }
167	        }
168	    }
